import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { FaCar, FaCalendarAlt, FaDollarSign } from 'react-icons/fa';

const BranchHeadDashboard = () => {
  const [stats, setStats] = useState({
    totalCars: 0,
    totalBookings: 0,
    revenue: 0
  });

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const [cars, bookings] = await Promise.all([
        axios.get('http://localhost:5000/api/cars'),
        axios.get('http://localhost:5000/api/bookings')
      ]);

      const revenue = bookings.data.data.reduce((sum, b) => sum + b.totalPrice, 0);

      setStats({
        totalCars: cars.data.count,
        totalBookings: bookings.data.data.length,
        revenue
      });
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  return (
    <div>
      <h1>Branch Head Dashboard</h1>
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon blue">
            <FaCar />
          </div>
          <div className="stat-info">
            <h3>Total Cars</h3>
            <p>{stats.totalCars}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon green">
            <FaCalendarAlt />
          </div>
          <div className="stat-info">
            <h3>Total Bookings</h3>
            <p>{stats.totalBookings}</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon orange">
            <FaDollarSign />
          </div>
          <div className="stat-info">
            <h3>Revenue</h3>
            <p>${stats.revenue.toLocaleString()}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BranchHeadDashboard;
